<template>
  <div
    id="e3"
    style="max-width: 400px; margin: 100px auto 0;"
    class="grey lighten-3 julian-ires"
  >
    <v-toolbar color="teal" dark>
      <v-toolbar-side-icon />
      <v-toolbar-title>
        <v-text-field
          v-model="key"
          label="iTunes Search Album"
          id="id"
          color="white"
          autocomplete="off"
        />
      </v-toolbar-title>
      <v-spacer />
      <v-btn @click="searchAl" icon>
        <v-icon>search</v-icon>
      </v-btn>
    </v-toolbar>
    <v-card>
      <v-container fluid grid-list-lg>
        <v-layout row wrap>
          <v-flex xs12>
            <v-card
              color="teal"
              class="white--text mb-4"
              v-for="result in results"
              :key="result.collectionId"
            >
              <a :href="result.artistViewUrl" target="_blank">
                <v-layout>
                  <v-flex xs5>
                    <v-img
                      :src="result.artworkUrl100"
                      height="125px"
                      contain
                    ></v-img>
                  </v-flex>
                  <v-flex xs7>
                    <v-card-title primary-title>
                      <div>
                        <div class="headline">{{ result.collectionName }}</div>
                        <div>{{ result.artistName }}</div>
                        <div>{{ result.releaseDate.slice(0, 4) }}</div>
                      </div>
                    </v-card-title>
                  </v-flex>
                </v-layout>
                <v-divider light></v-divider>
                <v-card-actions class="pa-3">
                  Rate this album
                  <v-spacer></v-spacer>
                  <v-icon color="yellow">star_border</v-icon>
                  <v-icon color="yellow">star_border</v-icon>
                  <v-icon color="yellow">star_border</v-icon>
                  <v-icon color="yellow">star_border</v-icon>
                  <v-icon>star_border</v-icon>
                </v-card-actions>
              </a>
            </v-card>
          </v-flex>
        </v-layout>
      </v-container>
    </v-card>
    <div>{{ error }}</div>
  </div>
</template>

<script>
import axios from "axios";

export default {
  data() {
    return {
      key: "",
      results: [],
      error: null
    };
  },
  metaInfo: {
    titleTemplate: "%s | iTunes"
  },
  methods: {
    searchAl() {
      axios
        .get(`https://itunes.apple.com/search?term=${this.key}&entity=album`)
        .then(res => (this.results = res.data.results))
        .catch(err => (this.error = err));
      this.key = "";
    }
  }
};
</script>

<style lang="scss" scoped>
.julian-ires {
  a {
    color: white;
    text-decoration: none;
  }
}
</style>
