<template>
  <div class="julian-crud">
    <v-container>
      <v-layout justify-center row wrap>
        <v-flex md10>
          <div>
            <v-form ref="form" v-model="valid" @submit.prevent="add">
              <v-text-field
                v-model="newTeam.name"
                label="Name"
                :counter="30"
                :rules="nameRules"
                prepend-icon="person"
                required
              />
              <v-text-field
                v-model="newTeam.email"
                label="Email"
                :rules="emailRules"
                prepend-icon="email"
                required
              />
              <v-text-field
                v-model="newTeam.position"
                label="Position"
                :rules="[v => !!v || 'Position is required']"
                prepend-icon="stars"
                required
              />
              <v-text-field
                v-model="newTeam.skills"
                label="Skills"
                :rules="[v => !!v || 'Skills is required']"
                prepend-icon="view_list"
                required
              />
              <v-btn :disabled="!valid" type="submit" small color="primary">
                Add
              </v-btn>
            </v-form>
            <div class="julian-table">
              <table class="mt-4">
                <tr>
                  <th>No</th>
                  <th>Name</th>
                  <th>Email</th>
                  <th>Position</th>
                  <th>Skills</th>
                  <th>Action</th>
                </tr>
                <tr v-for="(team, index) in teams" :key="team.id">
                  <td style="text-align:center;">
                    {{ index + 1 }}
                  </td>
                  <td>
                    {{ team.name }}
                  </td>
                  <td>
                    {{ team.email }}
                  </td>
                  <td>
                    {{ team.position }}
                  </td>
                  <td>
                    {{ team.skills }}
                  </td>
                  <td>
                    <v-btn small color="primary" @click="edit(team.id)">
                      edit
                    </v-btn>
                    <v-btn small color="error" @click="del(team.id)">
                      delete
                    </v-btn>
                  </td>
                </tr>
              </table>
            </div>
          </div>
        </v-flex>
      </v-layout>
    </v-container>
  </div>
</template>

<script>
export default {
  metaInfo: {
    titleTemplate: "%s | vuex"
  },
  data() {
    return {
      valid: true,
      newTeam: {
        id: "",
        name: "",
        email: "",
        position: "",
        skills: ""
      },
      nameRules: [
        v => !!v || "Name is required",
        v => (v && v.length <= 30) || "Name must be less than 10 characters"
      ],
      emailRules: [
        v => !!v || "E-mail is required",
        v => /.+@.+/.test(v) || "E-mail must be valid"
      ]
    };
  },
  computed: {
    teams() {
      return this.$store.state.teams;
    }
  },
  methods: {
    del(id) {
      this.$store.commit("del", id);
    },
    add() {
      this.$store.commit("add", this.newTeam);
      this.newTeam = {};
      this.$refs.form.reset();
    },
    edit(id) {
      this.$router.push(`/${id}`);
    }
  }
};
</script>

